export const paymentModule = new PaymentModule();

export function createHttpWalletProvider({
  baseUrl,
  getAuthToken,
  headers,
  telemetry,
  timeoutMs,
} = {}) {
  if (!baseUrl) throw new PaymentError('INVALID_INPUT', 'baseUrl is required');

  const buildHeaders = async () => {
    const h = {
      ...(typeof headers === 'function' ? await headers() : (headers || {})),
    };
    if (getAuthToken) {
      const t = await getAuthToken();
      if (t) h.Authorization = `Bearer ${t}`;
    }
    return h;
  };

  const provider = {
    async getBalance() {
      const h = await buildHeaders();
      return fetchJson(`${baseUrl}/wallet/balance`, { method: 'POST', headers: h, body: {}, timeoutMs: timeoutMs || 25000 });
    },

    async charge({ token, request }) {
      const h = await buildHeaders();
      h['X-Wallet-Token'] = token;
      h['Idempotency-Key'] = request.idempotencyKey;
      return fetchJson(`${baseUrl}/wallet/charge`, { method: 'POST', headers: h, body: request, timeoutMs: timeoutMs || 25000 });
    },

    async transfer({ token, request }) {
      const h = await buildHeaders();
      h['X-Wallet-Token'] = token;
      h['Idempotency-Key'] = request.idempotencyKey;
      return fetchJson(`${baseUrl}/wallet/transfer`, { method: 'POST', headers: h, body: request, timeoutMs: timeoutMs || 25000 });
    },

    async verifyIapReceipt({ platform, receipt, purchase, context }) {
      const h = await buildHeaders();
      return fetchJson(`${baseUrl}/iap/verify`, {
        method: 'POST',
        headers: h,
        body: { platform, receipt, purchase, context },
        timeoutMs: timeoutMs || 25000,
      });
    },
  };

  if (telemetry && telemetry.enabled && telemetry.endpoint) {
    const log = async (event) => {
      try {
        const h = await buildHeaders();
        await fetchJson(`${telemetry.endpoint}`, {
          method: 'POST',
          headers: h,
          body: { event },
          timeoutMs: timeoutMs || 10000,
        });
      } catch {}
    };
    paymentModule.onEvent((evt) => {
      const safe = redact(evt);
      log(safe);
    });
  }

  return provider;
}

export function usePaymentModule() {
  const [, setTick] = useState(0);
  const lastEventRef = useRef(null);

  useEffect(() => {
    const off = paymentModule.onEvent((evt) => {
      lastEventRef.current = evt;
      setTick((x) => x + 1);
    });
    return off;
  }, []);

  return useMemo(
    () => ({
      module: paymentModule,
      lastEvent: lastEventRef.current,
      locked: paymentModule.isLocked(),
      settings: paymentModule.getSettings(),
      iapProducts: paymentModule.getIapProducts(),
    }),
    [lastEventRef.current]
  );
}

export function PaymentDebugPanel({ visible = false } = {}) {
  const { lastEvent, locked, settings, iapProducts } = usePaymentModule();
  useEffect(() => {
    if (!visible) return;
    if (lastEvent?.type === 'IAP_INIT_ERROR') {
      Alert.alert('IAP Error', JSON.stringify(lastEvent.error));
    }
  }, [visible, lastEvent]);

  return null;
}

export function createClientAttestation({ deviceId, userId, sessionId } = {}) {
  const payload = {
    iss: MODULE_NS,
    aud: 'payments',
    deviceId: deviceId || null,
    userId: userId || null,
    sessionId: sessionId || null,
    iat: Math.floor(nowMs() / 1000),
    nonce: uuidv4(),
  };
  return createUnsignedJWS(payload);
}

